    related_articles: ["čl. 338. ZPP","čl. 339. ZPP","čl. 179. ZPP","čl. 350. ZPP","čl. 360. ZPP","čl. 2. ZPP","čl. 8. ZPP","čl. 337. ZPP","čl. 7. ZPP","čl. 131. ZPP"],
